    40→  const [preferences, setPreferences] = useState<BackupPreferences | null>(null);
    41→  const [autoSaveDirectory, setAutoSaveDirectory] = useState<FileSystemDirectoryHandle | null>(null);
    42→  const [customFilename, setCustomFilename] = useState('');
    43→  const [versionCount, setVersionCount] = useState(7);
    44→  const [recentlySaved, setRecentlySaved] = useState<'autoSave' | null>(null);
    45→
    46→  const loadData = useCallback(async () => {
    47→    const prefs = await loadPreferences();
    48→    setPreferences(prefs);
