    50→    // Initialize customization state
    51→    const filename = prefs.customFilename || 'Neuman.Brain';
    52→    const nameWithoutExt = filename.replace(/\.brain$/i, '');
    53→    setCustomFilename(nameWithoutExt);
    54→    setVersionCount(prefs.versionCount || 7);
    55→
    56→    // Restore saved directory handle
    57→    if (prefs.autoSaveEnabled) {
    58→      try {
    59→        const savedHandle = await getDirectoryHandle();
    60→        if (savedHandle) {
    61→          setAutoSaveDirectory(savedHandle);
    62→        }
    63→      } catch (error) {
    64→        log.warn('Could not restore auto-save directory handle', { error });
    65→      }
    66→    }
    67→  }, []);
    68→
    69→  useEffect(() => {
    70→    loadData();
    71→  }, [loadData]);
    72→
    73→  // Restore directory handle on mount
    74→  useEffect(() => {
    75→    const restoreDirectoryHandle = async () => {
    76→      try {
    77→        const savedHandle = await getDirectoryHandle();
    78→        if (savedHandle) {
    79→          setAutoSaveDirectory(savedHandle);
    80→        }
    81→      } catch (error) {
    82→        console.error('Failed to restore directory handle:', error);
    83→      }
    84→    };
    85→    restoreDirectoryHandle();
    86→  }, []);
    87→
    88→  const handleSetupAutoSave = async () => {
    89→    try {
    90→      const dirHandle = await requestAutoSaveDirectory();
    91→      setAutoSaveDirectory(dirHandle);
    92→
    93→      // Enable auto-save with directory handle
    94→      await autoSaveManager.enableLocal(dirHandle);
    95→
    96→      await loadData();
    97→      onRefresh();
    98→      onMessage({ type: 'success', text: 'Auto-save enabled! Your data will be automatically saved to the selected folder.' });
    99→    } catch (error) {
   100→      onMessage({ type: 'error', text: `${error}` });
   101→    }
   102→  };
   103→
   104→  const handleAutoSaveNow = async () => {
   105→    if (!autoSaveDirectory) {
   106→      onMessage({ type: 'error', text: 'Please configure auto-save directory first' });
   107→      return;
   108→    }
   109→
   110→    try {
   111→      onMessage({ type: 'info', text: 'Saving...' });
   112→      const result = await autoSave(autoSaveDirectory);
   113→
   114→      await addHistoryEntry({
   115→        filename: result.filename,
   116→        size: result.size,
   117→        compressed: result.compressed,
   118→        type: 'auto',
   119→        destination: 'local',
   120→        status: 'success',
   121→      });
   122→
   123→      await loadData();
   124→      onRefresh();
   125→      onMessage({ type: 'success', text: `Auto-saved: ${result.filename} (${formatFileSize(result.size)})` });
   126→    } catch (error) {
   127→      onMessage({ type: 'error', text: `Auto-save failed: ${error}` });
   128→    }
   129→  };
   130→
   131→  const toggleAutoSave = async () => {
   132→    if (!preferences) return;
   133→
   134→    if (preferences.autoSaveEnabled) {
   135→      // Disable auto-save
   136→      await autoSaveManager.disableLocal();
   137→      setAutoSaveDirectory(null);
   138→      await loadData();
   139→      onRefresh();
   140→      onMessage({ type: 'info', text: 'Auto-save disabled' });
   141→
   142→      setRecentlySaved('autoSave');
   143→      setTimeout(() => setRecentlySaved(null), 2000);
   144→    } else {
   145→      // Enable auto-save - request directory
   146→      await handleSetupAutoSave();
