/**
 * Auto-Save Settings Component
 *
 * Configures auto-save to local file system:
 * - Directory selection (File System Access API)
 * - Filename customization
 * - Version count
 * - Manual save trigger
 */

import React, { useState, useEffect, useCallback } from 'react';
import { motion } from 'framer-motion';
import {
  isFileSystemAccessSupported,
  requestAutoSaveDirectory,
  autoSave,
  getDirectoryHandle,
  formatFileSize,
} from '../../services/brainBackup';
import {
  loadPreferences,
  savePreferences,
  addHistoryEntry,
  type BackupPreferences,
} from '../../services/backupPreferences';
import { autoSaveManager } from '../../services/autoSave';
import { logger } from '../../services/logger';

const log = logger.module('AutoSaveSettings');

interface AutoSaveSettingsProps {
  onMessage: (message: { type: 'success' | 'error' | 'info' | 'warning'; text: string } | null) => void;
  onRefresh: () => void;
}

export const AutoSaveSettings: React.FC<AutoSaveSettingsProps> = ({
  onMessage,
  onRefresh,
}) => {
  const [preferences, setPreferences] = useState<BackupPreferences | null>(null);
  const [autoSaveDirectory, setAutoSaveDirectory] = useState<FileSystemDirectoryHandle | null>(null);
  const [customFilename, setCustomFilename] = useState('');
  const [versionCount, setVersionCount] = useState(7);
  const [recentlySaved, setRecentlySaved] = useState<'autoSave' | null>(null);

  const loadData = useCallback(async () => {
    const prefs = await loadPreferences();
    setPreferences(prefs);

    // Initialize customization state
    const filename = prefs.customFilename || 'Neuman.Brain';
    const nameWithoutExt = filename.replace(/\.brain$/i, '');
    setCustomFilename(nameWithoutExt);
    setVersionCount(prefs.versionCount || 7);

    // Restore saved directory handle
    if (prefs.autoSaveEnabled) {
      try {
        const savedHandle = await getDirectoryHandle();
        if (savedHandle) {
          setAutoSaveDirectory(savedHandle);
        }
      } catch (error) {
        log.warn('Could not restore auto-save directory handle', { error });
      }
    }
  }, []);

  useEffect(() => {
    loadData();
  }, [loadData]);

  // Restore directory handle on mount
  useEffect(() => {
    const restoreDirectoryHandle = async () => {
      try {
        const savedHandle = await getDirectoryHandle();
        if (savedHandle) {
          setAutoSaveDirectory(savedHandle);
        }
      } catch (error) {
        console.error('Failed to restore directory handle:', error);
      }
    };
    restoreDirectoryHandle();
  }, []);

  const handleSetupAutoSave = async () => {
    try {
      const dirHandle = await requestAutoSaveDirectory();
      setAutoSaveDirectory(dirHandle);

      // Enable auto-save with directory handle
      await autoSaveManager.enableLocal(dirHandle);

      await loadData();
      onRefresh();
      onMessage({ type: 'success', text: 'Auto-save enabled! Your data will be automatically saved to the selected folder.' });
    } catch (error) {
      onMessage({ type: 'error', text: `${error}` });
    }
  };

  const handleAutoSaveNow = async () => {
    if (!autoSaveDirectory) {
      onMessage({ type: 'error', text: 'Please configure auto-save directory first' });
      return;
    }

    try {
      onMessage({ type: 'info', text: 'Saving...' });
      const result = await autoSave(autoSaveDirectory);

      await addHistoryEntry({
        filename: result.filename,
        size: result.size,
        compressed: result.compressed,
        type: 'auto',
        destination: 'local',
        status: 'success',
      });

      await loadData();
      onRefresh();
      onMessage({ type: 'success', text: `Auto-saved: ${result.filename} (${formatFileSize(result.size)})` });
    } catch (error) {
      onMessage({ type: 'error', text: `Auto-save failed: ${error}` });
    }
  };

  const toggleAutoSave = async () => {
    if (!preferences) return;

    if (preferences.autoSaveEnabled) {
      // Disable auto-save
      await autoSaveManager.disableLocal();
      setAutoSaveDirectory(null);
      await loadData();
      onRefresh();
      onMessage({ type: 'info', text: 'Auto-save disabled' });

      setRecentlySaved('autoSave');
      setTimeout(() => setRecentlySaved(null), 2000);
    } else {
      // Enable auto-save - request directory
      await handleSetupAutoSave();
    }
  };

  const handleSaveCustomization = async () => {
    if (!preferences) return;

    if (!customFilename.trim()) {
      onMessage({ type: 'error', text: 'Filename cannot be empty' });
      return;
    }

    if (versionCount < 1 || versionCount > 100) {
      onMessage({ type: 'error', text: 'Version count must be between 1 and 100' });
      return;
    }

    try {
      const filenameWithExtension = `${customFilename.trim()}.brain`;

      await savePreferences({
        customFilename: filenameWithExtension,
        versionCount: versionCount,
      });

      await loadData();
      onRefresh();
      onMessage({ type: 'success', text: 'Auto-save preferences updated!' });
    } catch (error) {
      onMessage({ type: 'error', text: `Failed to save preferences: ${error}` });
    }
  };

  if (!preferences) {
    return null;
  }

  return (
    <>
      {/* Simple Auto-Save Card (for File System Access API browsers) */}
      {isFileSystemAccessSupported() && (
        <div className="bento-card p-6">
          <h2 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-4">
            Auto-Save
          </h2>
          <p className="text-text-light-secondary dark:text-text-dark-secondary mb-4">
            Automatically save backups to a folder on your computer
          </p>

          {!autoSaveDirectory ? (
            <motion.button
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
              onClick={handleSetupAutoSave}
              className="w-full p-4 rounded-lg bg-surface-dark dark:bg-surface-dark-elevated text-white hover:bg-border-dark dark:hover:bg-border-dark transition-colors"
            >
              📁 Choose Auto-Save Folder
            </motion.button>
          ) : (
            <div className="space-y-3">
              <div className="flex items-center gap-2 text-accent-green">
                <span>✅</span>
                <span>Auto-save folder configured</span>
              </div>
              <motion.button
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                onClick={handleAutoSaveNow}
                className="w-full p-4 rounded-lg bg-accent-green text-white hover:bg-accent-green-hover transition-colors"
              >
                💾 Save Now
              </motion.button>
            </div>
          )}
        </div>
      )}

      {/* Detailed Auto-Save Configuration */}
      <div className="bento-card p-6">
        <h2 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-4">
          Auto-Save to File
        </h2>

        {!isFileSystemAccessSupported() ? (
          <div className="p-4 bg-accent-yellow/10 border border-accent-yellow/30 rounded-lg">
            <p className="text-sm text-accent-yellow">
              <strong>⚠️ Not Supported in {navigator.userAgent.includes('Firefox') ? 'Firefox' : navigator.userAgent.includes('Safari') ? 'Safari' : 'this browser'}</strong>
              <br />
              Auto-save to file requires a Chromium-based browser (Chrome, Edge, Brave, Arc, Opera, etc.).
              <br />
              Your data is still automatically saved to IndexedDB. You can manually export backups anytime.
            </p>
          </div>
        ) : (
          <div className="space-y-4">
            {/* Enable/Disable Toggle */}
            <label className="flex items-center justify-between p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg cursor-pointer hover:bg-border-light dark:hover:bg-border-dark transition-colors">
              <div>
                <p className="font-medium text-text-light-primary dark:text-text-dark-primary">Enable Auto-Save</p>
                <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                  {preferences.autoSaveEnabled
                    ? 'Your data is automatically saved to the selected folder'
                    : 'Automatically save your data to a local file'}
                </p>
              </div>
              <div className="flex items-center gap-2">
                {recentlySaved === 'autoSave' && (
                  <span className="text-sm font-medium text-accent-green animate-fade-in">
                    ✓ Saved
                  </span>
                )}
                <input
                  type="checkbox"
                  checked={preferences.autoSaveEnabled}
                  onChange={toggleAutoSave}
                  className="w-6 h-6 rounded"
                />
              </div>
            </label>

            {/* Auto-Save Status */}
            {preferences.autoSaveEnabled && (
              <div className="p-4 bg-status-success-bg dark:bg-status-success-bg-dark border border-status-success-border dark:border-status-success-border-dark rounded-lg">
                <div className="flex items-start gap-3">
                  <span className="text-2xl">✅</span>
                  <div className="flex-1">
                    <p className="font-semibold text-status-success-text dark:text-status-success-text-dark mb-1">
                      Auto-Save Enabled
                    </p>
                    <p className="text-sm text-status-success-text dark:text-status-success-text-dark">
                      Your data is automatically backed up to your selected folder whenever changes are made.
                      {preferences.lastAutoSave && (
                        <>
                          <br />
                          <strong>Last auto-save:</strong> {new Date(preferences.lastAutoSave).toLocaleString()}
                        </>
                      )}
                    </p>
                    {preferences.customFilename && (
                      <p className="text-sm text-status-success-text dark:text-status-success-text-dark mt-2">
                        <strong>Filename:</strong> {preferences.customFilename}
                        <br />
                        <strong>Versions kept:</strong> {preferences.versionCount || 7}
                      </p>
                    )}
                  </div>
                </div>
              </div>
            )}

            {/* Customization Settings */}
            <div className="space-y-4">
              <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
                Customize Auto-Save
              </h3>

              {/* Filename Input */}
              <div>
                <label className="block text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
                  Backup Filename
                </label>
                <div className="flex items-center gap-2">
                  <input
                    type="text"
                    value={customFilename}
                    onChange={(e) => setCustomFilename(e.target.value)}
                    placeholder="Neuman"
                    className="flex-1 px-4 py-2 bg-white dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-magenta focus:border-transparent transition-all"
                  />
                  <span className="text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary">.brain</span>
                </div>
                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                  Enter the filename (e.g., "Neuman", "MyBackup"). The .brain extension is automatically added.
                </p>
              </div>

              {/* Version Count Input */}
              <div>
                <label className="block text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
                  Versions to Keep
                </label>
                <input
                  type="number"
                  min="1"
                  max="100"
                  value={versionCount}
                  onChange={(e) => setVersionCount(parseInt(e.target.value) || 7)}
                  className="w-full px-4 py-2 bg-white dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-magenta focus:border-transparent transition-all"
                />
                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                  Number of timestamped backups to keep in the hidden .neuman-backups folder (1-100)
                </p>
              </div>

              {/* Save Button */}
              <button
                onClick={handleSaveCustomization}
                className="w-full px-4 py-2 bg-accent-magenta hover:bg-accent-magenta-hover text-white rounded-lg font-medium shadow-soft hover:shadow-medium transition-all duration-200"
              >
                💾 Save Preferences
              </button>
            </div>

            {/* Manual Save Now Button */}
            {preferences.autoSaveEnabled && (
              <button
                onClick={handleAutoSaveNow}
                className="w-full px-4 py-3 bg-accent-cyan hover:bg-accent-cyan-hover text-white rounded-lg font-medium shadow-soft hover:shadow-medium transition-all duration-200"
              >
                💾 Save Now (Manual Trigger)
              </button>
            )}
          </div>
        )}
      </div>
    </>
  );
};

/**
 * BackupSettings Component
 *
 * Settings UI for backup configuration
 * - Enable/disable auto-save
 * - Configure save interval, versions, file name
 * - Test auto-save manually
 * - Change backup folder
 */

import { useState } from 'react';
import { useThemeStore } from '../stores/useThemeStore';
import { autoSaveManager } from '../services/autoSave';
import { requestAutoSaveDirectory } from '../services/brainBackup';

export function BackupSettings() {
  const backupPreferences = useThemeStore((state) => state.backupPreferences);
  const updateBackupPreferences = useThemeStore((state) => state.updateBackupPreferences);

  const [isSelecting, setIsSelecting] = useState(false);
  const [isTesting, setIsTesting] = useState(false);
  const [testMessage, setTestMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  /**
   * Handle folder selection
   */
  const handleSelectFolder = async () => {
    setIsSelecting(true);
    setTestMessage(null);

    try {
      const dirHandle = await requestAutoSaveDirectory();

      // Update preferences
      updateBackupPreferences({
        hasBackupFolder: true,
        backupFolderPath: dirHandle.name,
        autoSaveEnabled: true,
      });

      // Enable auto-save
      await autoSaveManager.enableLocal(dirHandle);

      setTestMessage({
        type: 'success',
        text: `Backup folder selected: ${dirHandle.name}`,
      });
    } catch (error) {
      if ((error as Error).name === 'AbortError') {
        // User cancelled - not an error
        setTestMessage({
          type: 'error',
          text: 'Folder selection cancelled',
        });
      } else {
        setTestMessage({
          type: 'error',
          text: `Error: ${(error as Error).message}`,
        });
      }
    } finally {
      setIsSelecting(false);
    }
  };

  /**
   * Handle toggle auto-save
   */
  const handleToggleAutoSave = async () => {
    if (backupPreferences.autoSaveEnabled) {
      await autoSaveManager.disableLocal();
      updateBackupPreferences({ autoSaveEnabled: false });
    } else {
      if (backupPreferences.hasBackupFolder) {
        // Re-enable with existing folder
        updateBackupPreferences({ autoSaveEnabled: true });
      } else {
        // Prompt to select folder
        await handleSelectFolder();
      }
    }
  };

  /**
   * Handle test auto-save
   */
  const handleTestSave = async () => {
    setIsTesting(true);
    setTestMessage(null);

    try {
      await autoSaveManager.saveNow();
      setTestMessage({
        type: 'success',
        text: 'Backup saved successfully!',
      });
    } catch (error) {
      setTestMessage({
        type: 'error',
        text: `Error: ${(error as Error).message}`,
      });
    } finally {
      setIsTesting(false);
    }
  };

  /**
   * Handle save interval change
   */
  const handleSaveIntervalChange = (value: number) => {
    updateBackupPreferences({ saveInterval: value * 1000 }); // Convert to ms
  };

  /**
   * Handle versions to keep change
   */
  const handleVersionsChange = (value: number) => {
    updateBackupPreferences({ versionsToKeep: value });
  };

  /**
   * Handle custom file name change
   * Strips any extension and stores just the base name, then appends .brain
   */
  const handleFileNameChange = (value: string) => {
    // Remove any .brain extension if user types it
    const baseName = value.replace(/\.brain$/i, '').trim();
    // Store with .brain extension
    updateBackupPreferences({ customFileName: baseName ? `${baseName}.brain` : 'Neuman.brain' });
  };

  /**
   * Get display filename (without .brain extension)
   */
  const getDisplayFileName = () => {
    return (backupPreferences.customFileName || 'Neuman.brain').replace(/\.brain$/i, '');
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h2 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
          Backup & Sync
        </h2>
        <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mt-1">
          Automatically backup your data to a cloud-synced folder (iCloud, Google Drive, OneDrive, Proton Drive, Dropbox)
        </p>
      </div>

      {/* Current Status */}
      <div className="bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-button p-4">
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center gap-2">
            <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
              Auto-Save Status
            </span>
            {backupPreferences.autoSaveEnabled && (
              <span className="px-2 py-0.5 text-xs font-medium bg-status-success/10 text-status-success rounded-button">
                Enabled
              </span>
            )}
            {!backupPreferences.autoSaveEnabled && (
              <span className="px-2 py-0.5 text-xs font-medium bg-status-warning/10 text-status-warning rounded-button">
                Disabled
              </span>
            )}
          </div>

          {/* Toggle */}
          <button
            onClick={handleToggleAutoSave}
            className={`relative inline-flex h-6 w-11 items-center rounded-full transition-all duration-standard ease-smooth ${
              backupPreferences.autoSaveEnabled
                ? 'bg-accent-blue'
                : 'bg-border-light dark:bg-border-dark'
            }`}
          >
            <span
              className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                backupPreferences.autoSaveEnabled ? 'translate-x-6' : 'translate-x-1'
              }`}
            />
          </button>
        </div>

        {/* Folder Path */}
        {backupPreferences.hasBackupFolder && (
          <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
            <span className="font-medium">Folder: </span>
            {backupPreferences.backupFolderPath || 'Not set'}
          </div>
        )}
      </div>

      {/* Folder Picker */}
      <div className="space-y-3">
        <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
          Backup Folder
        </label>
        <div className="flex gap-2">
          <button
            onClick={handleSelectFolder}
            disabled={isSelecting}
            className="px-4 py-2.5 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button text-sm font-medium disabled:opacity-50 disabled:cursor-not-allowed transition-all duration-standard ease-smooth"
          >
            {isSelecting ? 'Selecting...' : backupPreferences.hasBackupFolder ? 'Change Folder' : 'Choose Folder'}
          </button>

          {backupPreferences.hasBackupFolder && (
            <button
              onClick={handleTestSave}
              disabled={isTesting || !backupPreferences.autoSaveEnabled}
              className="px-4 py-2.5 bg-surface-light-elevated dark:bg-surface-dark-elevated hover:bg-surface-light dark:hover:bg-neutral-800 text-text-light-primary dark:text-text-dark-primary rounded-button text-sm font-medium disabled:opacity-50 disabled:cursor-not-allowed transition-all duration-standard ease-smooth border border-border-light dark:border-border-dark"
            >
              {isTesting ? 'Saving...' : 'Test Auto-Save'}
            </button>
          )}
        </div>

        {/* Test Message */}
        {testMessage && (
          <div
            className={`text-sm px-3 py-2 rounded-button ${
              testMessage.type === 'success'
                ? 'bg-status-success/10 text-status-success'
                : 'bg-status-error/10 text-status-error'
            }`}
          >
            {testMessage.text}
          </div>
        )}
      </div>

      {/* Configuration Options */}
      {backupPreferences.hasBackupFolder && (
        <div className="space-y-4 pt-4 border-t border-border-light dark:border-border-dark">
          <h3 className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
            Configuration
          </h3>

          {/* Save Interval */}
          <div className="space-y-2">
            <label className="block text-sm text-text-light-primary dark:text-text-dark-primary">
              Save Interval
              <span className="ml-2 text-xs text-text-light-secondary dark:text-text-dark-secondary">
                ({backupPreferences.saveInterval / 1000} seconds)
              </span>
            </label>
            <input
              type="range"
              min="10"
              max="300"
              step="10"
              value={backupPreferences.saveInterval / 1000}
              onChange={(e) => handleSaveIntervalChange(Number(e.target.value))}
              className="w-full h-2 bg-border-light dark:bg-border-dark rounded-button appearance-none cursor-pointer accent-accent-blue"
            />
            <div className="flex justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary">
              <span>10s</span>
              <span>5min</span>
            </div>
          </div>

          {/* Versions to Keep */}
          <div className="space-y-2">
            <label className="block text-sm text-text-light-primary dark:text-text-dark-primary">
              Versions to Keep
              <span className="ml-2 text-xs text-text-light-secondary dark:text-text-dark-secondary">
                ({backupPreferences.versionsToKeep} backups)
              </span>
            </label>
            <input
              type="range"
              min="1"
              max="30"
              step="1"
              value={backupPreferences.versionsToKeep}
              onChange={(e) => handleVersionsChange(Number(e.target.value))}
              className="w-full h-2 bg-border-light dark:bg-border-dark rounded-button appearance-none cursor-pointer accent-accent-blue"
            />
            <div className="flex justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary">
              <span>1</span>
              <span>30</span>
            </div>
          </div>

          {/* Custom File Name */}
          <div className="space-y-2">
            <label className="block text-sm text-text-light-primary dark:text-text-dark-primary">
              File Name
            </label>
            <div className="flex items-center gap-2">
              <input
                type="text"
                value={getDisplayFileName()}
                onChange={(e) => handleFileNameChange(e.target.value)}
                placeholder="Neuman"
                className="flex-1 px-3 py-2 text-sm rounded-button bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue"
              />
              <span className="text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary">.brain</span>
            </div>
            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
              Backup files will be named: {getDisplayFileName()}-YYYY-MM-DD-HHmmss.brain
            </p>
          </div>
        </div>
      )}

      {/* Documentation Link */}
      <div className="pt-4 border-t border-border-light dark:border-border-dark">
        <a
          href="/docs/backup-sync-guide"
          target="_blank"
          rel="noopener noreferrer"
          className="text-sm text-accent-blue hover:underline"
        >
          📖 View Backup & Sync Documentation →
        </a>
      </div>
    </div>
  );
}

